// LED Control Program for Microcontroller
// Common in embedded systems and IoT devices

#include <stdio.h>
#include <stdint.h>

// Memory-mapped register addresses (typical in embedded C)
#define LED_DIRECTION_REG ((volatile uint8_t*)0x1000)
#define LED_OUTPUT_REG ((volatile uint8_t*)0x1001)
#define LED_PIN_INPUT ((volatile uint8_t*)0x1002)

#define LED_ON 0x01
#define LED_OFF 0x00

void delay(int milliseconds) {
    // Simple software delay loop
    for(volatile int i = 0; i < milliseconds * 1000; i++);
}

void ledInitialize(void) {
    // Set LED pin as output (direction register)
    *LED_DIRECTION_REG = 0x01;
}

void ledTurnOn(void) {
    // Write to output register to turn LED on
    *LED_OUTPUT_REG = LED_ON;
}

void ledTurnOff(void) {
    // Write to output register to turn LED off
    *LED_OUTPUT_REG = LED_OFF;
}

int main(void) {
    ledInitialize();

    // Blink LED - common pattern in embedded systems
    while(1) {
        ledTurnOn();
        delay(500);
        ledTurnOff();
        delay(500);
    }

    return 0;
}

// Database Transaction Log Manager
// Similar to components in MySQL, PostgreSQL

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_TRANSACTIONS 1000
#define MAX_LOG_SIZE 10000

typedef struct {
    int transactionId;
    char operation[10];  // INSERT, UPDATE, DELETE
    char tableName[50];
    char timestamp[30];
    int status;  // 0=pending, 1=committed, 2=rolled back
} Transaction;

typedef struct {
    Transaction transactions[MAX_TRANSACTIONS];
    int count;
    FILE *logFile;
} LogManager;

void initLogManager(LogManager *manager, const char *filename) {
    manager->count = 0;
    manager->logFile = fopen(filename, "a");
    if (manager->logFile == NULL) {
        printf("Error: Cannot open log file\n");
        exit(1);
    }
}

int logTransaction(LogManager *manager, Transaction *trans) {
    if (manager->count >= MAX_TRANSACTIONS) {
        // Flush buffer to disk when full
        fflush(manager->logFile);
        manager->count = 0;
    }

    // Copy transaction to buffer
    memcpy(&manager->transactions[manager->count], trans, sizeof(Transaction));
    manager->count++;

    // Write to log file immediately (durable storage)
    fprintf(manager->logFile, "ID:%d|OP:%s|TABLE:%s|TIME:%s|STATUS:%d\n",
            trans->transactionId, trans->operation, trans->tableName,
            trans->timestamp, trans->status);

    return 1;
}

void closeLogManager(LogManager *manager) {
    if (manager->logFile != NULL) {
        fflush(manager->logFile);
        fclose(manager->logFile);
    }
}

int main() {
    LogManager lm;
    Transaction t1 = {1001, "INSERT", "users", "2024-01-15 10:30:00", 1};
    Transaction t2 = {1002, "UPDATE", "accounts", "2024-01-15 10:31:00", 1};

    initLogManager(&lm, "transaction.log");

    logTransaction(&lm, &t1);
    logTransaction(&lm, &t2);

    printf("Transactions logged successfully\n");

    closeLogManager(&lm);

    return 0;
}

